class Solution:
    def mincostTickets(self, days, costs):
        dayset = set(days)
        last = days[-1]
        from functools import lru_cache
        import sys
        sys.setrecursionlimit(10000)
        @lru_cache(maxsize=None)
        def cost(d):
            if d > last:
                return 0
            if d not in dayset:
                return cost(d + 1)
            return min(
                costs[0] + cost(d + 1),
                costs[1] + cost(d + 7),
                costs[2] + cost(d + 30),
            )
        return cost(1)

